	KUNIT_ASSERT_TRUE(test, parent_fd >= 0);

	task = pkm_lcs_kunit_kthread_run(pkm_lcs_kunit_symlink_sequence_source_thread,
			   &script, "pkm-lcs-kunit-open-rel-link-mid");
	KUNIT_ASSERT_FALSE(test, IS_ERR(task));

