	KUNIT_EXPECT_EQ(test, log.last_sequence, sequence_before);
	KUNIT_EXPECT_EQ(test, log.last_parent_depth, 2U);
	KUNIT_EXPECT_STREQ(test, log.last_child_name, value_name);
	KUNIT_EXPECT_STREQ(test, log.last_layer, "base");

