static void pkm_lcs_kunit_base_layer_metadata_refresh_caches_sd(
	struct kunit *test)
{
	static const char * const metadata_path[] = {
		"Machine", "System", "Registry", "Layers", "base"
	};
	static const u8 metadata_ancestors[5][PKM_LCS_GUID_BYTES] = {
		{ 1 },
		{ 0xb6, 0x10 },
		{ 0xb6, 0x11 },
		{ 0xb6, 0x12 },
		{ 0xb6 },
	};
	struct pkm_lcs_layer_snapshot snapshot = { };
	struct pkm_lcs_kunit_layer_metadata_refresh_source_script script = {
		.expected_guid = metadata_ancestors[4],
		.name = "base",
		.sd = pkm_lcs_kunit_owner_only_sd,
		.sd_len = sizeof(pkm_lcs_kunit_owner_only_sd),
		.stop_after_read_key = true,
	};
	struct task_struct *task;
	struct file file = { };
	const void *token;
	bool present = false;
	long fd;
	long ret;
	int thread_ret;

	pkm_lcs_kunit_flush_deferred_key_fd_release();
	pkm_lcs_kunit_reset_layer_table();
	pkm_lcs_kunit_setup_registered_source(test, &file, &token);
	script.file = &file;

	fd = pkm_lcs_kunit_publish_key_fd_from_path(
		1, KEY_QUERY_VALUE, metadata_path, metadata_ancestors,
		ARRAY_SIZE(metadata_ancestors));
	KUNIT_ASSERT_TRUE(test, fd >= 0);

	task = pkm_lcs_kunit_kthread_run(
		pkm_lcs_kunit_layer_metadata_refresh_source_thread, &script,
		"pkm-lcs-kunit-base-layer-refresh");
	KUNIT_ASSERT_FALSE(test, IS_ERR(task));
	ret = pkm_lcs_kunit_key_fd_refresh_layer_metadata((int)fd);
	thread_ret = pkm_lcs_kunit_kthread_stop(task);

	KUNIT_EXPECT_EQ(test, ret, 0L);
	KUNIT_EXPECT_EQ(test, thread_ret, 0);
	KUNIT_EXPECT_EQ(test, script.result, 0);
	KUNIT_EXPECT_EQ(test, script.reads, 1U);
	KUNIT_EXPECT_EQ(test, script.writes, 1U);

	KUNIT_ASSERT_EQ(test, pkm_lcs_source_layer_snapshot_acquire(&snapshot),
			0L);
	KUNIT_EXPECT_EQ(test, snapshot.layer_count, 1U);
	KUNIT_EXPECT_EQ(test, snapshot.metadata_count, 0U);
	KUNIT_ASSERT_TRUE(test, snapshot.base_metadata_present);
	KUNIT_ASSERT_EQ(test, snapshot.base_metadata_sd_len,
			sizeof(pkm_lcs_kunit_owner_only_sd));
	KUNIT_EXPECT_EQ(test,
			memcmp(snapshot.base_metadata_sd,
			       pkm_lcs_kunit_owner_only_sd,
			       snapshot.base_metadata_sd_len),
			0);
	pkm_lcs_source_layer_snapshot_release(&snapshot);

	KUNIT_ASSERT_EQ(test,
			pkm_lcs_layer_table_metadata_key_guid_present(
				metadata_ancestors[4], &present),
			0L);
	KUNIT_EXPECT_TRUE(test, present);

	KUNIT_EXPECT_EQ(test, close_fd((unsigned int)fd), 0);
	pkm_lcs_kunit_flush_deferred_key_fd_release();
	KUNIT_EXPECT_EQ(test, pkm_lcs_source_device_release_file(&file), 0);
	pkm_lcs_kunit_reset_source_table();
	pkm_lcs_kunit_reset_layer_table();
	kacs_rust_token_drop(token);
}

static void pkm_lcs_kunit_layer_metadata_refresh_malformed_sd_audits(
	struct kunit *test)
{
	static const char event_type[] = "LCS_SOURCE_VALIDATION_FAILURE";
	static const char validation_class[] =
		"malformed_layer_metadata_security_descriptor";
	static const char * const metadata_path[] = {
		"Machine", "System", "Registry", "Layers", "Policy"
	};
	static const u8 metadata_ancestors[5][PKM_LCS_GUID_BYTES] = {
		{ 1 },
		{ 0xf5, 0x10 },
		{ 0xf5, 0x11 },
		{ 0xf5, 0x12 },
		{ 0xf5 },
	};
	static const u8 malformed_sd[] = { 0x01, 0x02, 0x03 };
	struct pkm_lcs_rsi_layer_view layers[3] = { };
	struct pkm_lcs_kunit_layer_metadata_refresh_source_script script = {
		.expected_guid = metadata_ancestors[4],
		.name = "Policy",
		.sd = malformed_sd,
		.sd_len = sizeof(malformed_sd),
		.stop_after_read_key = true,
	};
	struct pkm_kmes_kunit_snapshot snapshot = { };
	char names[64] = { };
	struct task_struct *task;
	struct file file = { };
	const void *token;
	u8 *buffer;
	size_t written = 0;
	u32 header_size;
	u32 count = 0;
	u16 type_len;
	long fd;
	long ret;
	int thread_ret;

	pkm_lcs_kunit_flush_deferred_key_fd_release();
	pkm_lcs_kunit_reset_layer_table();
	pkm_lcs_kunit_setup_registered_source(test, &file, &token);
	script.file = &file;
	buffer = kzalloc(2048, GFP_KERNEL);
	KUNIT_ASSERT_NOT_NULL(test, buffer);
	KUNIT_ASSERT_EQ(test,
			pkm_lcs_layer_table_publish(
				"Policy", strlen("Policy"), 9, 1,
				metadata_ancestors[4],
				pkm_lcs_kunit_owner_only_sd,
				sizeof(pkm_lcs_kunit_owner_only_sd),
				pkm_lcs_kunit_system_sid,
				sizeof(pkm_lcs_kunit_system_sid)),
			0L);

	fd = pkm_lcs_kunit_publish_key_fd_from_path(
		1, KEY_QUERY_VALUE, metadata_path, metadata_ancestors,
		ARRAY_SIZE(metadata_ancestors));
	KUNIT_ASSERT_TRUE(test, fd >= 0);

	pkm_kmes_kunit_reset_all();
	task = pkm_lcs_kunit_kthread_run(
		pkm_lcs_kunit_layer_metadata_refresh_source_thread, &script,
		"pkm-lcs-kunit-layer-refresh-sd-bad");
	KUNIT_ASSERT_FALSE(test, IS_ERR(task));
	ret = pkm_lcs_kunit_key_fd_refresh_layer_metadata((int)fd);
	thread_ret = pkm_lcs_kunit_kthread_stop(task);

	KUNIT_EXPECT_EQ(test, ret, (long)-EIO);
	KUNIT_EXPECT_EQ(test, thread_ret, 0);
	KUNIT_EXPECT_EQ(test, script.result, 0);
	KUNIT_EXPECT_EQ(test, script.reads, 1U);
	KUNIT_EXPECT_EQ(test, script.writes, 1U);
	KUNIT_ASSERT_EQ(test,
			pkm_kmes_kunit_copy_latest_matching_event(
				KMES_ORIGIN_LCS, event_type,
				sizeof(event_type) - 1, buffer, 2048,
				&written, &snapshot),
			0);
	type_len = get_unaligned_le16(buffer + KMES_EVENT_TYPE_LEN_OFFSET);
	header_size = get_unaligned_le32(buffer + KMES_EVENT_HEADER_SIZE_OFFSET);
	KUNIT_ASSERT_EQ(test, type_len, (u16)(sizeof(event_type) - 1));
	KUNIT_ASSERT_TRUE(test, written > header_size);
	KUNIT_EXPECT_EQ(test,
			memcmp(buffer + KMES_EVENT_HEADER_BASE_SIZE, event_type,
			       type_len),
			0);
	KUNIT_EXPECT_EQ(test, buffer[header_size], 0x86);
	KUNIT_EXPECT_TRUE(test,
			  pkm_lcs_kunit_buffer_contains(
				  buffer, written, validation_class));
	KUNIT_EXPECT_TRUE(test,
			  pkm_lcs_kunit_buffer_contains_bytes(
				  buffer, written, metadata_ancestors[4],
				  sizeof(metadata_ancestors[4])));

	KUNIT_ASSERT_EQ(test,
			pkm_lcs_source_layer_snapshot_copy(
				layers, ARRAY_SIZE(layers), names, sizeof(names),
				&count),
			0L);
	KUNIT_ASSERT_EQ(test, count, 2U);
	KUNIT_EXPECT_STREQ(test, layers[1].name, "Policy");
	KUNIT_EXPECT_EQ(test, layers[1].precedence, 9U);
	KUNIT_EXPECT_EQ(test, layers[1].enabled, 1U);

	KUNIT_EXPECT_EQ(test, close_fd((unsigned int)fd), 0);
	pkm_lcs_kunit_flush_deferred_key_fd_release();
	KUNIT_EXPECT_EQ(test, pkm_lcs_source_device_release_file(&file), 0);
	pkm_lcs_kunit_reset_source_table();
	pkm_lcs_kunit_reset_layer_table();
	kfree(buffer);
	kacs_rust_token_drop(token);
}

static void pkm_lcs_kunit_layer_metadata_set_security_refreshes_sd(
	struct kunit *test)
{
	static const char * const metadata_path[] = {
		"Machine", "System", "Registry", "Layers", "Policy"
	};
	static const u8 metadata_ancestors[5][PKM_LCS_GUID_BYTES] = {
		{ 1 },
		{ 0xf6, 0x10 },
		{ 0xf6, 0x11 },
		{ 0xf6, 0x12 },
		{ 0xf6 },
	};
	static const u8 old_sd[] = {
		0x01, 0x00, 0x00, 0x80, 0x14, 0x00, 0x00, 0x00,
		0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
		0x00, 0x00, 0x00, 0x00,
		0x01, 0x01, 0x00, 0x00, 0x00, 0x00, 0x00, 0x05,
		0x12, 0x00, 0x00, 0x00,
	};
	static const u8 new_sd[] = {
		0x01, 0x00, 0x00, 0x80, 0x14, 0x00, 0x00, 0x00,
		0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
		0x00, 0x00, 0x00, 0x00,
		0x01, 0x01, 0x00, 0x00, 0x00, 0x00, 0x00, 0x01,
		0x00, 0x00, 0x00, 0x00,
	};
	struct pkm_lcs_kunit_usercopy_ctx ctx = { };
	struct pkm_lcs_usercopy_ops ops = pkm_lcs_kunit_usercopy_ops(&ctx);
	struct reg_set_security_args args = {
		.security_info = OWNER_SECURITY_INFORMATION,
		.sd_len = sizeof(new_sd),
		.sd_ptr = (u64)(unsigned long)new_sd,
		.txn_fd = -1,
	};
	struct pkm_lcs_kunit_set_security_layer_refresh_source_script script = {
		.set_security = {
			.expected_guid = metadata_ancestors[4],
			.existing_sd = old_sd,
			.existing_sd_len = sizeof(old_sd),
			.expected_merged_sd = new_sd,
			.expected_merged_sd_len = sizeof(new_sd),
		},
		.refresh = {
			.expected_guid = metadata_ancestors[4],
			.name = "Policy",
			.sd = new_sd,
			.sd_len = sizeof(new_sd),
			.precedence = 17,
			.enabled = 0,
			.precedence_present = true,
			.enabled_present = true,
		},
	};
	struct pkm_lcs_layer_snapshot snapshot = { };
	struct task_struct *task;
	struct file file = { };
	const void *token;
	long fd;
	long ret;
	int thread_ret;

	pkm_lcs_kunit_flush_deferred_key_fd_release();
	pkm_lcs_kunit_reset_layer_table();
	pkm_lcs_kunit_setup_registered_source(test, &file, &token);
	script.file = &file;
	KUNIT_ASSERT_EQ(test,
			pkm_lcs_layer_table_publish(
				"Policy", strlen("Policy"), 9, 1,
				metadata_ancestors[4], old_sd, sizeof(old_sd),
				pkm_lcs_kunit_system_sid,
				sizeof(pkm_lcs_kunit_system_sid)),
			0L);

	fd = pkm_lcs_kunit_publish_key_fd_from_path(
		1, WRITE_OWNER, metadata_path, metadata_ancestors,
		ARRAY_SIZE(metadata_ancestors));
	KUNIT_ASSERT_TRUE(test, fd >= 0);

	task = pkm_lcs_kunit_kthread_run(
		pkm_lcs_kunit_set_security_layer_refresh_source_thread,
		&script, "pkm-lcs-kunit-set-sd-layer-refresh");
	KUNIT_ASSERT_FALSE(test, IS_ERR(task));
	ret = pkm_lcs_kunit_key_fd_set_security((int)fd, &ops, &args);
	thread_ret = pkm_lcs_kunit_kthread_stop(task);

	KUNIT_EXPECT_EQ(test, ret, 0L);
	KUNIT_EXPECT_EQ(test, thread_ret, 0);
	KUNIT_EXPECT_EQ(test, script.result, 0);
	KUNIT_EXPECT_EQ(test, script.reads, 6U);
	KUNIT_EXPECT_EQ(test, script.writes, 6U);
	KUNIT_EXPECT_NE(test,
			script.set_security.observed_last_write_time, 0ULL);
	KUNIT_EXPECT_EQ(test, ctx.reads, 1U);

	KUNIT_ASSERT_EQ(test,
			pkm_lcs_source_layer_snapshot_acquire(&snapshot),
			0L);
	KUNIT_ASSERT_EQ(test, snapshot.layer_count, 2U);
	KUNIT_ASSERT_EQ(test, snapshot.metadata_count, 1U);
	KUNIT_EXPECT_STREQ(test, snapshot.layers[1].name, "Policy");
	KUNIT_EXPECT_EQ(test, snapshot.layers[1].precedence, 17U);
	KUNIT_EXPECT_EQ(test, snapshot.layers[1].enabled, 0U);
	KUNIT_EXPECT_STREQ(test, snapshot.metadata[0].name, "Policy");
	KUNIT_EXPECT_EQ(test, snapshot.metadata[0].sd_len, sizeof(new_sd));
	KUNIT_EXPECT_EQ(test,
			memcmp(snapshot.metadata[0].sd, new_sd, sizeof(new_sd)),
			0);
	pkm_lcs_source_layer_snapshot_release(&snapshot);

	KUNIT_EXPECT_EQ(test, close_fd((unsigned int)fd), 0);
	pkm_lcs_kunit_flush_deferred_key_fd_release();
	KUNIT_EXPECT_EQ(test, pkm_lcs_source_device_release_file(&file), 0);
	pkm_lcs_kunit_reset_source_table();
	pkm_lcs_kunit_reset_layer_table();
	kacs_rust_token_drop(token);
}

static void pkm_lcs_kunit_delete_layer_orchestration_aborts_before_broadcast(
	struct kunit *test)
{
	static const u8 root_guid[PKM_LCS_TRANSACTION_HIVE_ROOT_GUID_BYTES] = {
		1
	};
	static const u8 layer_guid[RSI_GUID_SIZE] = { 0xc3 };
	struct pkm_lcs_delete_layer_orchestration_result result = { };
	struct pkm_lcs_transaction_fd_snapshot txn_snapshot = { };
	struct pkm_lcs_source_fd_snapshot source_snapshot = { };
	struct pkm_lcs_kunit_delete_layer_source_script script = { };
	struct reg_txn_status_args status = { };
	struct task_struct *task;
	struct file file = { };
	const void *token;
	u32 count = 0;
	int thread_ret;
	long txn_fd;
	long ret;

	pkm_lcs_kunit_reset_layer_table();
	pkm_lcs_kunit_setup_registered_source(test, &file, &token);
	KUNIT_ASSERT_EQ(test,
			pkm_lcs_layer_table_publish(
				"Policy", strlen("Policy"), 9, 1, layer_guid,
				pkm_lcs_kunit_owner_only_sd,
				sizeof(pkm_lcs_kunit_owner_only_sd),
				pkm_lcs_kunit_system_sid,
				sizeof(pkm_lcs_kunit_system_sid)),
			0L);

	txn_fd = pkm_lcs_reg_begin_transaction();
	KUNIT_ASSERT_TRUE(test, txn_fd >= 0);
	KUNIT_ASSERT_EQ(test,
			pkm_lcs_transaction_fd_snapshot((int)txn_fd,
							&txn_snapshot),
			0L);
	KUNIT_ASSERT_EQ(test,
			pkm_lcs_source_bound_transaction_acquire(1, &count),
			0L);
	KUNIT_ASSERT_EQ(test,
			pkm_lcs_transaction_fd_complete_first_bind(
				(int)txn_fd, txn_snapshot.transaction_id, 1,
				root_guid),
			0L);
	pkm_lcs_kunit_append_set_value_log_for_layer(test, (int)txn_fd,
						     root_guid, "Policy",
						     77);

	KUNIT_EXPECT_EQ(test,
			pkm_lcs_source_delete_layer_orchestrate_timeout(
				"base", strlen("base"), 1000, &result),
			(long)-EINVAL);
	pkm_lcs_kunit_source_fd_snapshot(&file, &source_snapshot);
	KUNIT_EXPECT_EQ(test, source_snapshot.queued_request_count, 0U);
	KUNIT_EXPECT_EQ(test, source_snapshot.in_flight_request_count, 0U);
	KUNIT_ASSERT_EQ(test,
			pkm_lcs_transaction_fd_snapshot((int)txn_fd,
							&txn_snapshot),
			0L);
	KUNIT_EXPECT_EQ(test, txn_snapshot.state, REG_TXN_ACTIVE_BOUND);

	script.file = &file;
	script.expected_layer_name = "policy";
	script.expected_abort_txn_id = txn_snapshot.transaction_id;
	script.status = RSI_OK;
	task = pkm_lcs_kunit_kthread_run(
		pkm_lcs_kunit_delete_layer_source_thread, &script,
		"pkm-lcs-kunit-layer-orch");
	KUNIT_ASSERT_FALSE(test, IS_ERR(task));
	memset(&result, 0, sizeof(result));
	ret = pkm_lcs_source_delete_layer_orchestrate_timeout(
		"policy", strlen("policy"), 1000, &result);
	thread_ret = pkm_lcs_kunit_kthread_stop(task);

	KUNIT_EXPECT_EQ(test, ret, 0L);
	KUNIT_EXPECT_EQ(test, thread_ret, 0);
	KUNIT_EXPECT_EQ(test, script.result, 0);
	KUNIT_EXPECT_TRUE(test, script.abort_before_delete_observed);
	KUNIT_EXPECT_EQ(test, script.reads, 2U);
	KUNIT_EXPECT_EQ(test, script.writes, 2U);
	KUNIT_EXPECT_EQ(test, result.inspected_transaction_count, 1U);
	KUNIT_EXPECT_EQ(test, result.affected_bound_transaction_count, 1U);
	KUNIT_EXPECT_EQ(test, result.abort_dispatched_count, 1U);
	KUNIT_EXPECT_EQ(test, result.layer_table_entry_removed, 1U);
	KUNIT_EXPECT_EQ(test, result.active_source_count, 1U);
	KUNIT_EXPECT_EQ(test, result.completed_source_count, 1U);
	KUNIT_EXPECT_EQ(test, result.orphaned_guid_count, 0U);
	KUNIT_EXPECT_EQ(test, result.marked_fd_count, 0U);
	KUNIT_EXPECT_EQ(test, result.immediate_drop_count, 0U);
	KUNIT_EXPECT_EQ(test, result.generation_hive_count, 1U);
	KUNIT_EXPECT_EQ(test, result.watch_overflow_count, 0U);

	KUNIT_ASSERT_EQ(test,
			pkm_lcs_transaction_fd_status((int)txn_fd, &status),
			0L);
	KUNIT_EXPECT_EQ(test, status.state, REG_TXN_ABORTED);
	KUNIT_EXPECT_EQ(test, status.terminal_errno, EINVAL);

	KUNIT_EXPECT_EQ(test, close_fd((unsigned int)txn_fd), 0);
	flush_delayed_fput();
	KUNIT_EXPECT_EQ(test, pkm_lcs_source_device_release_file(&file), 0);
	pkm_lcs_kunit_reset_source_table();
	pkm_lcs_kunit_reset_layer_table();
	kacs_rust_token_drop(token);
}

static void pkm_lcs_kunit_delete_layer_orchestration_overflows_watches(
	struct kunit *test)
{
	static const char layer_name[] = "policy";
	static const u8 layer_guid[RSI_GUID_SIZE] = { 0xc4 };
	static const char * const path[] = { "Machine", "Software" };
	static const u8 ancestors[2][PKM_LCS_GUID_BYTES] = {
		{ 1 },
		{ 0xc4, 0x01 },
	};
	struct pkm_lcs_delete_layer_orchestration_result result = { };
	struct pkm_lcs_kunit_delete_layer_source_script script = {
		.expected_layer_name = layer_name,
		.status = RSI_OK,
	};
	struct reg_notify_args notify = {
		.filter = REG_NOTIFY_VALUE,
	};
	u8 record[16] = { };
	struct task_struct *task;
	struct file file = { };
	const void *token;
	u64 generation_before = 0;
	u64 generation_after = 0;
	long fd;
	long ret;
	int thread_ret;

	pkm_lcs_kunit_reset_layer_table();
	pkm_lcs_kunit_setup_registered_source(test, &file, &token);
	KUNIT_ASSERT_EQ(test,
			pkm_lcs_layer_table_publish(
				"Policy", strlen("Policy"), 9, 1, layer_guid,
				pkm_lcs_kunit_owner_only_sd,
				sizeof(pkm_lcs_kunit_owner_only_sd),
				pkm_lcs_kunit_system_sid,
				sizeof(pkm_lcs_kunit_system_sid)),
			0L);
	fd = pkm_lcs_kunit_publish_key_fd_from_path(
		1, KEY_NOTIFY, path, ancestors, ARRAY_SIZE(ancestors));
	KUNIT_ASSERT_TRUE(test, fd >= 0);
	KUNIT_ASSERT_EQ(test, pkm_lcs_kunit_key_fd_notify((int)fd, &notify),
			0L);
	KUNIT_ASSERT_EQ(test,
			pkm_lcs_kunit_source_hive_generation_snapshot(
				1, ancestors[0], &generation_before),
			0L);

	script.file = &file;
	task = pkm_lcs_kunit_kthread_run(
		pkm_lcs_kunit_delete_layer_source_thread, &script,
		"pkm-lcs-kunit-layer-overflow");
	KUNIT_ASSERT_FALSE(test, IS_ERR(task));
	ret = pkm_lcs_source_delete_layer_orchestrate_timeout(
		layer_name, strlen(layer_name), 1000, &result);
	thread_ret = pkm_lcs_kunit_kthread_stop(task);

	KUNIT_EXPECT_EQ(test, ret, 0L);
	KUNIT_EXPECT_EQ(test, thread_ret, 0);
	KUNIT_EXPECT_EQ(test, script.result, 0);
	KUNIT_EXPECT_EQ(test, result.layer_table_entry_removed, 1U);
	KUNIT_EXPECT_EQ(test, result.active_source_count, 1U);
	KUNIT_EXPECT_EQ(test, result.completed_source_count, 1U);
	KUNIT_EXPECT_EQ(test, result.generation_hive_count, 1U);
	KUNIT_EXPECT_EQ(test, result.watch_overflow_count, 1U);
	KUNIT_ASSERT_EQ(test,
			pkm_lcs_kunit_source_hive_generation_snapshot(
				1, ancestors[0], &generation_after),
			0L);
	KUNIT_EXPECT_EQ(test, generation_after, generation_before + 1);
	KUNIT_ASSERT_EQ(test,
			pkm_lcs_kunit_key_fd_read((int)fd, record,
						  sizeof(record), true),
			(ssize_t)8);
	KUNIT_EXPECT_EQ(test, get_unaligned_le32(record), 8U);
	KUNIT_EXPECT_EQ(test, get_unaligned_le16(record + 4),
			REG_WATCH_OVERFLOW);
	KUNIT_EXPECT_EQ(test, get_unaligned_le16(record + 6), 0U);

	KUNIT_EXPECT_EQ(test, close_fd((unsigned int)fd), 0);
	pkm_lcs_kunit_flush_deferred_key_fd_release();
	KUNIT_EXPECT_EQ(test, pkm_lcs_source_device_release_file(&file), 0);
	pkm_lcs_kunit_reset_source_table();
	pkm_lcs_kunit_reset_layer_table();
	kacs_rust_token_drop(token);
}

static void pkm_lcs_kunit_source_dispatch_transaction_control_frames(
	struct kunit *test)
{
	struct pkm_lcs_source_enqueue_result begin = { };
	struct pkm_lcs_source_enqueue_result commit = { };
	struct pkm_lcs_source_enqueue_result abort = { };
	struct pkm_lcs_source_fd_snapshot snapshot = { };
	size_t payload_offset = RSI_REQUEST_HEADER_SIZE;
	u8 out[64];
	struct file file = { };
	const void *token;

	pkm_lcs_kunit_setup_registered_source(test, &file, &token);

	KUNIT_ASSERT_EQ(test,
			pkm_lcs_source_dispatch_begin_transaction_request(
				1, 0x0102030405060708ULL,
				RSI_TXN_READ_WRITE, &begin),
			0L);
	KUNIT_EXPECT_EQ(test, begin.request_id, 0ULL);
	KUNIT_EXPECT_EQ(test, begin.txn_id, 0ULL);
	KUNIT_EXPECT_EQ(test, begin.op_code, (u16)RSI_BEGIN_TRANSACTION);
	KUNIT_EXPECT_EQ(test, begin.queue_depth, 1U);
	KUNIT_EXPECT_EQ(test, begin.in_flight_count, 1U);
	KUNIT_EXPECT_EQ(test, begin.next_request_id, 1ULL);

	KUNIT_ASSERT_EQ(test,
			pkm_lcs_source_dispatch_commit_transaction_request(
				1, 0x1112131415161718ULL, &commit),
			0L);
	KUNIT_EXPECT_EQ(test, commit.request_id, 1ULL);
	KUNIT_EXPECT_EQ(test, commit.txn_id, 0x1112131415161718ULL);
	KUNIT_EXPECT_EQ(test, commit.op_code, (u16)RSI_COMMIT_TRANSACTION);
	KUNIT_EXPECT_EQ(test, commit.queue_depth, 2U);
	KUNIT_EXPECT_EQ(test, commit.in_flight_count, 2U);
	KUNIT_EXPECT_EQ(test, commit.next_request_id, 2ULL);

	KUNIT_ASSERT_EQ(test,
			pkm_lcs_source_dispatch_abort_transaction_request(
				1, 0x2122232425262728ULL, &abort),
			0L);
	KUNIT_EXPECT_EQ(test, abort.request_id, 2ULL);
	KUNIT_EXPECT_EQ(test, abort.txn_id, 0x2122232425262728ULL);
	KUNIT_EXPECT_EQ(test, abort.op_code, (u16)RSI_ABORT_TRANSACTION);
	KUNIT_EXPECT_EQ(test, abort.queue_depth, 3U);
	KUNIT_EXPECT_EQ(test, abort.in_flight_count, 3U);
	KUNIT_EXPECT_EQ(test, abort.next_request_id, 3ULL);

	memset(out, 0, sizeof(out));
	KUNIT_ASSERT_EQ(test,
			pkm_lcs_kunit_source_device_read_file(&file, out,
							      sizeof(out),
							      true),
			(ssize_t)begin.len);
	KUNIT_EXPECT_EQ(test,
			get_unaligned_le32(out + RSI_REQUEST_TOTAL_LEN_OFFSET),
			(u32)(RSI_REQUEST_HEADER_SIZE + sizeof(u64) +
			      sizeof(u32)));
	KUNIT_EXPECT_EQ(test,
			get_unaligned_le64(out + RSI_REQUEST_ID_OFFSET), 0ULL);
	KUNIT_EXPECT_EQ(test,
			get_unaligned_le16(out + RSI_REQUEST_OP_CODE_OFFSET),
			(u16)RSI_BEGIN_TRANSACTION);
	KUNIT_EXPECT_EQ(test,
			get_unaligned_le64(out + RSI_REQUEST_TXN_ID_OFFSET),
			0ULL);
	KUNIT_EXPECT_EQ(test, get_unaligned_le64(out + payload_offset),
			0x0102030405060708ULL);
	KUNIT_EXPECT_EQ(test,
			get_unaligned_le32(out + payload_offset + sizeof(u64)),
			(u32)RSI_TXN_READ_WRITE);

	memset(out, 0, sizeof(out));
	KUNIT_ASSERT_EQ(test,
			pkm_lcs_kunit_source_device_read_file(&file, out,
							      sizeof(out),
							      true),
			(ssize_t)commit.len);
	KUNIT_EXPECT_EQ(test,
			get_unaligned_le64(out + RSI_REQUEST_ID_OFFSET), 1ULL);
	KUNIT_EXPECT_EQ(test,
			get_unaligned_le16(out + RSI_REQUEST_OP_CODE_OFFSET),
			(u16)RSI_COMMIT_TRANSACTION);
	KUNIT_EXPECT_EQ(test,
			get_unaligned_le64(out + RSI_REQUEST_TXN_ID_OFFSET),
			0x1112131415161718ULL);
	KUNIT_EXPECT_EQ(test, get_unaligned_le64(out + payload_offset),
			0x1112131415161718ULL);

	memset(out, 0, sizeof(out));
	KUNIT_ASSERT_EQ(test,
			pkm_lcs_kunit_source_device_read_file(&file, out,
							      sizeof(out),
							      true),
			(ssize_t)abort.len);
	KUNIT_EXPECT_EQ(test,
			get_unaligned_le64(out + RSI_REQUEST_ID_OFFSET), 2ULL);
	KUNIT_EXPECT_EQ(test,
			get_unaligned_le16(out + RSI_REQUEST_OP_CODE_OFFSET),
			(u16)RSI_ABORT_TRANSACTION);
	KUNIT_EXPECT_EQ(test,
			get_unaligned_le64(out + RSI_REQUEST_TXN_ID_OFFSET),
			0x2122232425262728ULL);
	KUNIT_EXPECT_EQ(test, get_unaligned_le64(out + payload_offset),
			0x2122232425262728ULL);

	pkm_lcs_kunit_source_fd_snapshot(&file, &snapshot);
	KUNIT_EXPECT_EQ(test, snapshot.queued_request_count, 0U);
	KUNIT_EXPECT_EQ(test, snapshot.in_flight_request_count, 3U);
	KUNIT_EXPECT_EQ(test, snapshot.next_request_id, 3ULL);

	KUNIT_EXPECT_EQ(test, pkm_lcs_source_device_release_file(&file), 0);
	pkm_lcs_kunit_reset_source_table();
	kacs_rust_token_drop(token);
}

static void pkm_lcs_kunit_source_abort_response_releases_no_wait_record(
	struct kunit *test)
{
	struct pkm_lcs_source_response_result response_result = { };
	struct pkm_lcs_source_fd_snapshot snapshot = { };
	struct pkm_lcs_source_enqueue_result abort = { };
	u8 response[RSI_MIN_RESPONSE_SIZE];
	u8 out[64];
	struct file file = { };
	const void *token;
	size_t response_len;

	pkm_lcs_kunit_setup_registered_source(test, &file, &token);
	KUNIT_ASSERT_EQ(test,
			pkm_lcs_source_dispatch_abort_transaction_request(
				1, 0x3132333435363738ULL, &abort),
			0L);
	KUNIT_EXPECT_EQ(test, abort.request_id, 0ULL);
	KUNIT_EXPECT_EQ(test, abort.txn_id, 0x3132333435363738ULL);
	KUNIT_EXPECT_EQ(test, abort.op_code, (u16)RSI_ABORT_TRANSACTION);
	KUNIT_EXPECT_EQ(test, abort.in_flight_count, 1U);

	KUNIT_ASSERT_EQ(test,
			pkm_lcs_kunit_source_device_read_file(&file, out,
							      sizeof(out),
							      true),
			(ssize_t)abort.len);
	pkm_lcs_kunit_source_fd_snapshot(&file, &snapshot);
	KUNIT_EXPECT_EQ(test, snapshot.queued_request_count, 0U);
	KUNIT_EXPECT_EQ(test, snapshot.in_flight_request_count, 1U);

	pkm_lcs_kunit_build_status_response(test, response, sizeof(response),
					    abort.request_id, abort.op_code,
					    RSI_OK, &response_len);
	KUNIT_EXPECT_EQ(test,
			pkm_lcs_kunit_source_device_write_file(
				&file, response, response_len, false,
				&response_result),
			(ssize_t)response_len);
	KUNIT_EXPECT_EQ(test, response_result.request_id, abort.request_id);
	KUNIT_EXPECT_EQ(test, response_result.txn_id, abort.txn_id);
	KUNIT_EXPECT_EQ(test, response_result.request_op_code,
			(u16)RSI_ABORT_TRANSACTION);
	KUNIT_EXPECT_EQ(test, response_result.response_op_code,
			(u16)RSI_ABORT_TRANSACTION_RESPONSE);
	KUNIT_EXPECT_EQ(test, response_result.status, (u32)RSI_OK);
	KUNIT_EXPECT_FALSE(test, response_result.malformed_source_data);
	KUNIT_EXPECT_FALSE(test, response_result.caller_waiter_attached);
	KUNIT_EXPECT_EQ(test, response_result.in_flight_count, 0U);
	pkm_lcs_kunit_source_fd_snapshot(&file, &snapshot);
	KUNIT_EXPECT_EQ(test, snapshot.queued_request_count, 0U);
	KUNIT_EXPECT_EQ(test, snapshot.in_flight_request_count, 0U);

	KUNIT_EXPECT_EQ(test, pkm_lcs_source_device_release_file(&file), 0);
	pkm_lcs_kunit_reset_source_table();
	kacs_rust_token_drop(token);
}

